import os
import sys

sys.path.insert(0, os.path.dirname(__file__))
from _allow_hook_harness import run_hook, cleanup, fresh_ids, stderr_has_usage_error

AC_UID = "54184514d342dd03"
AC_TYPE = "hook"


def test_AC14():
    r"""
    GIVEN: empty / vacuous re: operand inputs that name no concrete command:
             (a) 're:'      empty body — post-re-strip pattern is the empty
                            string, which the shell Point-C fallback (lines
                            127-130) currently re-coerces back to the universal
                            wildcard
             (b) re:''      empty single-quoted body — post-strip pattern is the
                            two literal quote chars (vacuous; names no command;
                            under re.search matches 0/5 unrelated probes so NOT
                            match-all but IS under-specified)
             (c) re:""      empty double-quoted body
    WHEN:  the hook runs for EACH input independently
    THEN:  EACH input is REFUSED:
             legacy_written == False, sentinel_written == False,
             stderr contains usage error, exit 0.
           The refuse decision for (a) MUST occur BEFORE the Point-C empty-
           PATTERN fallback (which must be DELETED — point_c_deleted == True)
           so an empty post-strip body can no longer become the universal
           wildcard (empty_post_strip_refuses_before_fallback == True).
           For (b)/(c) the refuse rationale is VACUOUS-no-command-named (an
           empty/quote-only regex body names no concrete command token),
           distinct from the match-breadth rationale of AC13.

    must_refuse_inputs: ['re:', "re:''", 're:""']
    """
    # (a) empty body, (b) empty single-quoted body, (c) empty double-quoted body.
    must_refuse = ["re:", "re:''", 're:""']
    for body in must_refuse:
        sid, task_id = fresh_ids()
        try:
            r = run_hook(f"/allow {body}", sid, task_id)
            assert r["exit"] == 0, f"{body!r}: expected exit 0, got {r['exit']}"
            assert r["legacy_written"] is False, (
                f"{body!r}: MUST refuse — empty/vacuous re: body must not become "
                f"the wildcard via a Point-C fallback (no legacy flag)")
            assert r["sentinel_written"] is False, f"{body!r}: MUST refuse (no sentinel)"
            assert stderr_has_usage_error(r["stderr"]), (
                f"{body!r}: usage error expected; stderr={r['stderr']!r}")
        finally:
            cleanup(sid, task_id)
